// Try to simplify select where the condition is a select.
// (X && Y) ? true : Y --> Y (commuted 2 ways)
// This is equivalent to: (X ? Y : false) ? true : Y
// When X is true: Y ? true : Y -> Y
// When X is false: false ? true : Y -> Y
static Value *foldSelectWithSelectCond(Value *Cond, Value *TrueVal,
                                       Value *FalseVal) {
  // Check for booleans only.
  if (!Cond->getType()->isIntOrIntVectorTy(1) ||
      !TrueVal->getType()->isIntOrIntVectorTy(1) ||
      Cond->getType() != TrueVal->getType())
    return nullptr;

  // This is a boolean select of bits.  Check if either operand is a select.
  Value *InnerCond, *InnerTrue, *InnerFalse;
  if (!match(Cond, m_Select(m_Value(InnerCond), m_Value(InnerTrue),
                            m_Value(InnerFalse))))
    return nullptr;

  // Analyze the inner select.
  // For: (X ? Y : false) ? true : Y
  // Simplify to: Y
  if (match(InnerFalse, m_ZeroInt()) && match(TrueVal, m_One())) {
    // Check if (InnerTrue == FalseVal) && (InnerCond is X)
    if (InnerTrue == FalseVal)
      return FalseVal;
  }

  // For: (X ? true : Y) ? true : Y  ? This doesn't work, let's check:
  // If X=true: true ? true : Y -> true != Y
  // If X=false: Y ? true : Y -> Y
  // So this doesn't simplify to Y

  // Commutations - handle when X is used on the false side:
  // (X ? false : Y) ? true : Y
  if (match(InnerTrue, m_ZeroInt()) && match(TrueVal, m_One())) {
    if (InnerFalse == FalseVal)
      return FalseVal;
  }

  return nullptr;
}

